let allEvents = [];
let offset = 0;
const count = 50;

while (true) {
  const result = await Memento.plugins.calendar.getEvents({offset, count});
  allEvents = allEvents.concat(result.data);

  if (!result.hasMore) break;
  offset += count;
}

setResult(`共加载 ${allEvents.length} 个事件`);

const startDate = await Memento.system.getCustomDate({relativePosition: 'startOfWeek', format: 'iso'});
const weekEnd = await Memento.system.getCustomDate({relativePosition: 'endOfWeek', format: 'iso'});
const endDate = weekEnd.replace(/T.*/, 'T23:59:59.000Z');
const events = await Memento.plugins.calendar.getEventsByDateRange({startDate: startDate, endDate: endDate});
setResult(`本周有 ${events.length} 个事件`);

const startDate = await Memento.system.getCustomDate({relativePosition: 'startOfWeek', format: 'iso'});
const weekEnd = await Memento.system.getCustomDate({relativePosition: 'endOfWeek', format: 'iso'});
const endDate = weekEnd.replace(/T.*/, 'T23:59:59.000Z');
const result = await Memento.plugins.calendar.getEventsByDateRange({startDate, endDate, offset: 0, count: 20});
setResult(`本周共 ${result.total} 个事件，当前返回 ${result.data.length} 个`);

const startDate = await Memento.system.getCustomDate({relativePosition: 'startOfMonth', format: 'iso'});
const monthEnd = await Memento.system.getCustomDate({relativePosition: 'endOfMonth', format: 'iso'});
const endDate = monthEnd.replace(/T.*/, 'T23:59:59.000Z');

let allEvents = [];
let offset = 0;
const count = 30;

while (true) {
  const result = await Memento.plugins.calendar.getEventsByDateRange({startDate, endDate, offset, count});
  allEvents = allEvents.concat(result.data);

  if (!result.hasMore) break;
  offset += count;
}

setResult(`本月共加载 ${allEvents.length} 个事件`);

const today = await Memento.system.getCustomDate({relativePosition: 'startOfDay', format: 'iso'});
const startTime = today.replace(/T.*/, 'T09:00:00.000Z');
const event = await Memento.plugins.calendar.createEvent({title: '项目会议', description: '讨论Q1计划', startTime: startTime});
setResult(`事件已创建: ${event.id}`);

const today = await Memento.system.getCustomDate({relativePosition: 'startOfDay', format: 'iso'});
const startTime = today.replace(/T.*/, 'T14:00:00.000Z');
const endTime = today.replace(/T.*/, 'T16:00:00.000Z');
const event = await Memento.plugins.calendar.createEvent({title: '重要会议', description: '年度规划', startTime: startTime, endTime: endTime, reminderMinutes: 15});
setResult('已创建事件，将提前15分钟提醒');

const event = await Memento.plugins.calendar.findEventBy({field: 'id', value: 'evt123'});
if (event) {
  setResult(`找到事件: ${event.title}，开始时间: ${event.startTime}`);
} else {
  setResult('未找到该事件');
}

const event = await Memento.plugins.calendar.findEventById({id: 'evt123'});
if (event) {
  setResult(`事件标题: ${event.title}, 开始时间: ${event.startTime}`);
} else {
  setResult('事件不存在');
}
